            'sort_by' => 'nullable|in:name,price,created_at,relevance',
            'sort_order' => 'nullable|in:asc,desc',
            'per_page' => 'nullable|integer|min:1|max:100',
        ]);

        $name = $validated['name'] ?? null;
        $category = $validated['category'] ?? null;
        $minPrice = $validated['min_price'] ?? null;
        $maxPrice = $validated['max_price'] ?? null;
        $sortBy = $validated['sort_by'] ?? 'relevance';
        $sortOrder = $validated['sort_order'] ?? 'desc';
        $perPage = $validated['per_page'] ?? 20;

        $bindings = [];
        $conditions = [];
        $selectFields = [
            'p.id',
            'p.name',
            'p.description',
            'p.price',
            'p.sku',
            'p.stock_quantity',
            'p.image_url',
            'p.created_at',
            'c.name AS category_name',
            'c.id AS category_id',
        ];

        // Build relevance score for name search
        if ($name) {
            $selectFields[] = DB::raw("
                (
                    CASE
                        WHEN LOWER(p.name) = LOWER(?) THEN 100
                        WHEN LOWER(p.name) LIKE LOWER(?) THEN 75
                        WHEN LOWER(p.name) LIKE LOWER(?) THEN 50
                        ELSE 0
                    END
                    +
                    CASE
                        WHEN LOWER(p.description) LIKE LOWER(?) THEN 25
                        ELSE 0
                    END
                ) AS relevance_score
            ");
            $bindings[] = $name;                    // exact match
            $bindings[] = $name . '%';              // starts with
            $bindings[] = '%' . $name . '%';        // contains in name
            $bindings[] = '%' . $name . '%';        // contains in description

            $conditions[] = '(LOWER(p.name) LIKE LOWER(?) OR LOWER(p.description) LIKE LOWER(?))';
            $bindings[] = '%' . $name . '%';
            $bindings[] = '%' . $name . '%';
        } else {
            $selectFields[] = DB::raw('0 AS relevance_score');
        }

        // Category filter
        if ($category) {
            $conditions[] = '(LOWER(c.name) = LOWER(?) OR LOWER(c.slug) = LOWER(?))';
            $bindings[] = $category;
            $bindings[] = $category;
        }

        // Price range filter
        if ($minPrice !== null) {
            $conditions[] = 'p.price >= ?';
            $bindings[] = $minPrice;
        }

        if ($maxPrice !== null) {
            $conditions[] = 'p.price <= ?';
            $bindings[] = $maxPrice;
        }

        // Always filter active products
        $conditions[] = 'p.is_active = 1';

        $whereClause = count($conditions) > 0
            ? 'WHERE ' . implode(' AND ', $conditions)
            : '';

        // Determine sort
        $allowedSorts = [
            'name' => 'p.name',
            'price' => 'p.price',
            'created_at' => 'p.created_at',
            'relevance' => 'relevance_score',
        ];

        $orderByColumn = $allowedSorts[$sortBy] ?? 'relevance_score';
        $orderDirection = strtoupper($sortOrder) === 'ASC' ? 'ASC' : 'DESC';

        $selectFieldsStr = implode(', ', array_map(function ($field) {
            return $field instanceof \Illuminate\Database\Query\Expression
                ? $field->getValue(DB::connection()->getQueryGrammar())
                : $field;
        }, $selectFields));

        $sql = "
            SELECT {$selectFieldsStr}
            FROM products p
            LEFT JOIN categories c ON p.category_id = c.id
            {$whereClause}
            ORDER BY {$orderByColumn} {$orderDirection}, p.name ASC
        ";

        // Get total count for pagination
        $countSql = "
            SELECT COUNT(*) AS total
            FROM products p
            LEFT JOIN categories c ON p.category_id = c.id
            {$whereClause}
        ";

        // Count bindings exclude the select-level bindings (relevance score params)
        $countBindings = [];
        if ($name) {
            // The count query only uses WHERE bindings, not SELECT bindings
            $countBindings[] = '%' . $name . '%';
            $countBindings[] = '%' . $name . '%';
        }
        if ($category) {
            $countBindings[] = $category;
            $countBindings[] = $category;
        }
        if ($minPrice !== null) {
            $countBindings[] = $minPrice;
        }
        if ($maxPrice !== null) {
            $countBindings[] = $maxPrice;
        }

        $totalResult = DB::selectOne($countSql, $countBindings);
        $total = $totalResult->total ?? 0;

        // Apply pagination
        $page = max(1, (int) $request->input('page', 1));
        $offset = ($page - 1) * $perPage;

        $sql .= " LIMIT ? OFFSET ?";
        $bindings[] = (int) $perPage;
        $bindings[] = (int) $offset;

        $products = DB::select($sql, $bindings);

